import React, { useState, useEffect } from 'react';
import { API_ENDPOINTS, BACKEND_BASE_URL } from '../config/api';

const Banner = () => {
  const [banner, setBanner] = useState(null);

  useEffect(() => {
    fetchBanner();
  }, []);

  const fetchBanner = async () => {
    try {
      const response = await fetch(API_ENDPOINTS.BANNERS);
      const data = await response.json();
      if (data.records && data.records.length > 0) {
        const bannerData = data.records[0];
        const imageUrl = bannerData.image_url.startsWith('http') 
          ? bannerData.image_url 
          : `${BACKEND_BASE_URL}/${bannerData.image_url}`;
        setBanner({ ...bannerData, image_url: imageUrl });
      }
    } catch (error) {
      console.error('Error fetching banner:', error);
    }
  };

  if (!banner) return null;

  return (
    <section className="mb-8">
      <div className="relative w-full h-64 md:h-80 rounded-xl overflow-hidden group cursor-pointer">
        <span className="iconify i-heroicons:chevron-right-20-solid flex-shrink-0 h-5 w-5 absolute left-4 top-1/2 -translate-y-1/2 text-white" aria-hidden="true"></span>
        <img src={banner.image_url} alt={banner.title || 'Banner'} className="w-full h-full object-cover" />
        <span className="iconify i-heroicons:chevron-right-20-solid flex-shrink-0 h-5 w-5 absolute right-4 top-1/2 -translate-y-1/2 text-white" aria-hidden="true"></span>
      </div>
    </section>
  );
};

export default Banner;
